export enum Gender {
  MALE = 'MALE',
  FEMALE = 'FEMALE'
}

export interface Player {
  id: string;
  name: string;
  gender: Gender;
}

export interface Team {
  player1: Player;
  player2: Player;
}

export interface Match {
  id: string;
  teamA: Team;
  teamB: Team;
  type: MatchType;
  timestamp: number;
}

export interface ScheduleItem extends Match {
  sequence: number;
  message?: string; // For explaining forced moves (e.g. "Continuous Play Bonus")
}

export enum MatchType {
  RANDOM = '一般隨機',
  MENS_DOUBLES = '男雙',
  WOMENS_DOUBLES = '女雙',
  MIXED_DOUBLES = '混雙'
}

import { Player, Team, Match, MatchType, Gender, ScheduleItem } from '../types';

// Fisher-Yates Shuffle
const shuffle = <T,>(array: T[]): T[] => {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
};

// Helper to create a unique key for a team (sorted IDs)
const getTeamKey = (p1: Player, p2: Player): string => {
  return [p1.id, p2.id].sort().join('-');
};

const createMatch = (t1: [Player, Player], t2: [Player, Player], type: MatchType): Match => ({
    id: Date.now().toString() + Math.random().toString(),
    teamA: { player1: t1[0], player2: t1[1] },
    teamB: { player1: t2[0], player2: t2[1] },
    type,
    timestamp: Date.now(),
});

// Single generation attempt
const generateCandidate = (players: Player[], type: MatchType): { matches: Match[], waiting: Player[], error: string | null } => {
  let pool = [...players];
  const matches: Match[] = [];

  // Filter logic
  if (type === MatchType.MENS_DOUBLES) {
    pool = pool.filter(p => p.gender === Gender.MALE);
  } else if (type === MatchType.WOMENS_DOUBLES) {
    pool = pool.filter(p => p.gender === Gender.FEMALE);
  }

  // Basic validation should be done by caller, but safe to check pool size logic for Mixed
  if (type === MatchType.MIXED_DOUBLES) {
    let males = shuffle(players.filter(p => p.gender === Gender.MALE));
    let females = shuffle(players.filter(p => p.gender === Gender.FEMALE));

    while (males.length >= 2 && females.length >= 2) {
      matches.push(createMatch([males.pop()!, females.pop()!], [males.pop()!, females.pop()!], type));
    }
  } else {
    // Standard / Single Gender
    let processingPool = shuffle(pool);
    while (processingPool.length >= 4) {
      matches.push(createMatch(
          [processingPool.pop()!, processingPool.pop()!], 
          [processingPool.pop()!, processingPool.pop()!], 
          type
      ));
    }
  }

  // Calculate waiting
  const playingIds = new Set(matches.flatMap(m => [m.teamA.player1.id, m.teamA.player2.id, m.teamB.player1.id, m.teamB.player2.id]));
  const waiting = players.filter(p => !playingIds.has(p.id));

  if (matches.length === 0 && type === MatchType.MIXED_DOUBLES) {
      return { matches: [], waiting: players, error: '混雙需要至少 2 男 2 女！' };
  }

  return { matches, waiting, error: null };
};

export const generateMatches = (
  players: Player[],
  type: MatchType,
  previousMatches: Match[] = []
): { matches: Match[]; waiting: Player[]; error: string | null } => {

  // 1. Initial Validation
  let poolCount = players.length;
  if (type === MatchType.MENS_DOUBLES) poolCount = players.filter(p => p.gender === Gender.MALE).length;
  if (type === MatchType.WOMENS_DOUBLES) poolCount = players.filter(p => p.gender === Gender.FEMALE).length;

  if (poolCount < 4) {
    if (type === MatchType.MENS_DOUBLES) return { matches: [], waiting: players, error: '男生人數不足 4 人，無法進行男雙！' };
    if (type === MatchType.WOMENS_DOUBLES) return { matches: [], waiting: players, error: '女生人數不足 4 人，無法進行女雙！' };
    return { matches: [], waiting: players, error: '人數不足，至少需要 4 人才能開始比賽！' };
  }

  // 2. Build avoidance set from previous matches
  const avoidKeys = new Set<string>();
  previousMatches.forEach(m => {
    avoidKeys.add(getTeamKey(m.teamA.player1, m.teamA.player2));
    avoidKeys.add(getTeamKey(m.teamB.player1, m.teamB.player2));
  });

  // 3. Try to find the best shuffle (least overlap with previous)
  let bestResult: { matches: Match[], waiting: Player[], error: string | null } | null = null;
  let minOverlap = Infinity;

  // If we have history to avoid, try multiple times. Otherwise just once is enough for random.
  const ATTEMPTS = avoidKeys.size > 0 ? 50 : 1;

  for (let i = 0; i < ATTEMPTS; i++) {
    const result = generateCandidate(players, type);

    if (result.error) return result; // Should have been caught by initial validation, but return if error

    // Calculate overlap score
    let currentOverlap = 0;
    result.matches.forEach(m => {
        if (avoidKeys.has(getTeamKey(m.teamA.player1, m.teamA.player2))) currentOverlap++;
        if (avoidKeys.has(getTeamKey(m.teamB.player1, m.teamB.player2))) currentOverlap++;
    });

    if (currentOverlap < minOverlap) {
        minOverlap = currentOverlap;
        bestResult = result;
    }

    // Found a perfect non-overlapping set? Stop early.
    if (minOverlap === 0) break;
  }

  return bestResult || { matches: [], waiting: players, error: '生成失敗' };
};

// --- SCHEDULE GENERATOR ---

interface PlayerStats {
  player: Player;
  played: number;
  consecutivePlays: number;
  consecutiveRests: number;
  owePlay: number; // Logic: If rested 2, must play 2. This tracks how many games strictly owed.
  oweRest: number; // Logic: If played 2, must rest 2. This tracks rests owed.
}

export const generateSchedule = (
  allPlayers: Player[],
  rounds: number,
  shuffleTeams: boolean, // If true, teams are randomized every match. If false, we try to keep pairs? (Simplifying: Always random pair among selected 4 for now)
  type: MatchType
): { schedule: ScheduleItem[], error: string | null } => {

  // 1. Filter Pool
  let pool = [...allPlayers];
  if (type === MatchType.MENS_DOUBLES) pool = pool.filter(p => p.gender === Gender.MALE);
  if (type === MatchType.WOMENS_DOUBLES) pool = pool.filter(p => p.gender === Gender.FEMALE);

  if (pool.length < 4) return { schedule: [], error: '人數不足 4 人，無法排程' };
  if (type === MatchType.MIXED_DOUBLES) {
     const m = pool.filter(p => p.gender === Gender.MALE).length;
     const f = pool.filter(p => p.gender === Gender.FEMALE).length;
     if (m < 2 || f < 2) return { schedule: [], error: '混雙需要至少 2 男 2 女' };
  }

  // 2. Initialize Stats
  const statsMap = new Map<string, PlayerStats>();
  pool.forEach(p => {
    statsMap.set(p.id, { 
      player: p, 
      played: 0, 
      consecutivePlays: 0, 
      consecutiveRests: 0,
      owePlay: 0,
      oweRest: 0
    });
  });

  const schedule: ScheduleItem[] = [];

  // Calculate total games needed: (Players * Rounds) / 4
  // Example: 8 players, 2 rounds -> (16 slots) -> 4 games. Everyone plays 2.
  // Example: 5 players, 2 rounds -> (10 slots) -> 3 games (12 slots). Everyone plays ~2.
  const totalSlotsNeeded = pool.length * rounds;
  const totalMatches = Math.ceil(totalSlotsNeeded / 4);

  for (let mIdx = 0; mIdx < totalMatches; mIdx++) {
    const currentStats = Array.from(statsMap.values());

    // --- SELECTION LOGIC ---
    let candidates: PlayerStats[] = [];

    // Separate into Must Play, Must Rest, and Neutral
    // Logic: 
    // If owePlay > 0 -> Priority High
    // If oweRest > 0 -> Exclude (unless we run out of people)

    // Sort logic score (Lower is better/more likely to be picked)
    const getScore = (s: PlayerStats): number => {
       if (s.oweRest > 0) return 1000; // Try very hard not to pick
       if (s.owePlay > 0) return -1000; // Must pick
       if (s.consecutiveRests >= 2) return -500; // Urgent to pick (Rule: Rest 2 -> Play 2)

       // General fairness
       return s.played * 10 - s.consecutiveRests; 
    };

    // Sort by score
    currentStats.sort((a, b) => {
        const scoreA = getScore(a);
        const scoreB = getScore(b);
        if (scoreA !== scoreB) return scoreA - scoreB;
        return Math.random() - 0.5; // Random tie-breaker
    });

    // Select Top 4 valid players
    let selectedStats: PlayerStats[] = [];

    if (type === MatchType.MIXED_DOUBLES) {
        // Complex logic for Mixed: Need 2 M, 2 F.
        const males = currentStats.filter(s => s.player.gender === Gender.MALE);
        const females = currentStats.filter(s => s.player.gender === Gender.FEMALE);

        // Take top 2 males and top 2 females based on score
        if (males.length < 2 || females.length < 2) break; // Should not happen given init check
        selectedStats = [...males.slice(0, 2), ...females.slice(0, 2)];
    } else {
        // Standard Top 4
        selectedStats = currentStats.slice(0, 4);
    }

    // Emergency Check: If we picked someone with oweRest > 0 because we didn't have enough people?
    // It's allowed by the sort order (score 1000 is high but if everyone is 1000, they get picked).

    const selectedIds = new Set(selectedStats.map(s => s.player.id));

    // --- FORM TEAMS ---
    // Shuffle the 4 selected players
    const matchPlayers = shuffle(selectedStats.map(s => s.player));
    let t1: [Player, Player], t2: [Player, Player];

    if (type === MatchType.MIXED_DOUBLES) {
       const m = matchPlayers.filter(p => p.gender === Gender.MALE);
       const f = matchPlayers.filter(p => p.gender === Gender.FEMALE);
       t1 = [m[0], f[0]];
       t2 = [m[1], f[1]];
    } else {
       t1 = [matchPlayers[0], matchPlayers[1]];
       t2 = [matchPlayers[2], matchPlayers[3]];
    }

    schedule.push({
        ...createMatch(t1, t2, type),
        sequence: mIdx + 1
    });

    // --- UPDATE STATS ---
    statsMap.forEach(stat => {
        if (selectedIds.has(stat.player.id)) {
            // Selected
            stat.played++;

            // Check for "Rest 2 -> Play 2" Rule Activation
            // If they were just resting (conRest >= 2) and got picked, they now owe 1 more game
            if (stat.consecutiveRests >= 2 && stat.owePlay === 0) {
               stat.owePlay = 1; // Played this one, need 1 more
            }

            stat.consecutivePlays++;
            stat.consecutiveRests = 0;

            // Decrement Play Debt
            if (stat.owePlay > 0) stat.owePlay--;

            // Check for "Play 2 -> Rest 2" Rule Activation
            if (stat.consecutivePlays >= 2) {
               stat.oweRest = 2; // Must rest next 2
            }
        } else {
            // Resting
            stat.consecutivePlays = 0;
            stat.consecutiveRests++;

            // Decrement Rest Debt
            if (stat.oweRest > 0) stat.oweRest--;

            // Check for "Rest 2 -> Play 2" Rule (Activation Logic is in Selection Scoring/owePlay)
            // But we can ensure they are prioritized next by the getScore function logic (-500)
        }
    });
  }

  return { schedule, error: null };
};

import React, { useState, useEffect } from 'react';
import { Player, Gender, Match, MatchType, ScheduleItem } from './types';
import { generateMatches, generateSchedule } from './services/matchService';
import Court from './components/Court';
import PlayerCard from './components/PlayerCard';
import { Trash2, Shuffle, UserPlus, Users, History, Coffee, XCircle, RefreshCw, X, Calendar, Settings, ArrowRight } from 'lucide-react';

interface HistoryPlayer {
  name: string;
  gender: Gender;
}

const App: React.FC = () => {
  const [players, setPlayers] = useState<Player[]>([]);
  const [newName, setNewName] = useState('');
  const [newGender, setNewGender] = useState<Gender>(Gender.MALE);

  // Single Match Mode State
  const [matches, setMatches] = useState<Match[]>([]);
  const [waitingPlayers, setWaitingPlayers] = useState<Player[]>([]);

  // Schedule Mode State
  const [schedule, setSchedule] = useState<ScheduleItem[]>([]);
  const [rounds, setRounds] = useState<number>(2);
  const [scheduleType, setScheduleType] = useState<MatchType>(MatchType.RANDOM);
  const [isScheduleMode, setIsScheduleMode] = useState<boolean>(false);

  const [lastMatchType, setLastMatchType] = useState<MatchType | null>(null);

  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [playerHistory, setPlayerHistory] = useState<HistoryPlayer[]>([]);

  // Load history on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('badminton_player_history');
    if (savedHistory) {
      try {
        setPlayerHistory(JSON.parse(savedHistory));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, []);

  // Save history helper
  const addToHistory = (name: string, gender: Gender) => {
    setPlayerHistory(prev => {
      const exists = prev.some(p => p.name === name);
      if (exists) return prev;
      const newHistory = [...prev, { name, gender }];
      localStorage.setItem('badminton_player_history', JSON.stringify(newHistory));
      return newHistory;
    });
  };

  const removeFromHistory = (e: React.MouseEvent, nameToDelete: string) => {
    e.stopPropagation();
    const newHistory = playerHistory.filter(p => p.name !== nameToDelete);
    setPlayerHistory(newHistory);
    localStorage.setItem('badminton_player_history', JSON.stringify(newHistory));
  };

  const handleAddPlayer = (e: React.FormEvent) => {
    e.preventDefault();
    addPlayerLogic(newName, newGender);
    setNewName('');
  };

  const addPlayerLogic = (name: string, gender: Gender) => {
    if (!name.trim()) return;

    // Prevent duplicates in current list
    if (players.some(p => p.name === name)) {
      setErrorMsg(`${name} 已經在名單中囉！`);
      setTimeout(() => setErrorMsg(null), 2000);
      return;
    }

    const newPlayer: Player = {
      id: Date.now().toString() + Math.random().toString(),
      name: name.trim(),
      gender: gender,
    };

    setPlayers([...players, newPlayer]);
    addToHistory(name.trim(), gender);
  };

  const handleAddAllHistory = () => {
    const currentNames = new Set(players.map(p => p.name));
    const playersToAdd: Player[] = [];

    playerHistory.forEach((h, index) => {
      if (!currentNames.has(h.name)) {
        playersToAdd.push({
          id: Date.now().toString() + '-' + index + '-' + Math.random().toString().substr(2, 5),
          name: h.name,
          gender: h.gender,
        });
      }
    });

    if (playersToAdd.length > 0) {
      setPlayers(prev => [...prev, ...playersToAdd]);
    } else {
       setErrorMsg('所有歷史球員都在名單內囉！');
       setTimeout(() => setErrorMsg(null), 2000);
    }
  };

  const handleDeletePlayer = (id: string) => {
    setPlayers(players.filter(p => p.id !== id));
  };

  // --- SINGLE MATCH GENERATION ---
  const handleGenerate = (type: MatchType) => {
    setErrorMsg(null);
    setIsScheduleMode(false);
    setLastMatchType(type);
    setMatches([]);
    setWaitingPlayers([]);

    const result = generateMatches(players, type);

    if (result.error) {
      setErrorMsg(result.error);
      setTimeout(() => setErrorMsg(null), 3000);
    } else {
      setMatches(result.matches);
      setWaitingPlayers(result.waiting);
      scrollToResults();
    }
  };

  const handleReshuffle = () => {
    if (!lastMatchType) return;
    setErrorMsg(null);

    const result = generateMatches(players, lastMatchType, matches);

    if (result.error) {
        setErrorMsg(result.error);
        setTimeout(() => setErrorMsg(null), 3000);
    } else {
        setMatches(result.matches);
        setWaitingPlayers(result.waiting);
    }
  };

  // --- SCHEDULE GENERATION ---
  const handleGenerateSchedule = () => {
    setErrorMsg(null);
    setIsScheduleMode(true);
    setSchedule([]);

    const result = generateSchedule(players, rounds, true, scheduleType);

    if (result.error) {
        setErrorMsg(result.error);
        setTimeout(() => setErrorMsg(null), 3000);
    } else {
        setSchedule(result.schedule);
        scrollToResults();
    }
  };

  const scrollToResults = () => {
    setTimeout(() => {
        document.getElementById('results-section')?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  return (
    <div className="min-h-screen bg-slate-50 font-q pb-20">
      {/* Header */}
      <header className="bg-white shadow-sm border-b border-slate-200 sticky top-0 z-30">
        <div className="max-w-4xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-500 p-2 rounded-xl text-white shadow-emerald-200 shadow-lg">
               <Shuffle size={24} />
            </div>
            <h1 className="text-2xl font-bold text-slate-700 tracking-tight">
              菜雞互啄 <span className="text-emerald-500">分隊趣</span>
            </h1>
          </div>
          <div className="text-xs text-slate-400 font-medium bg-slate-100 px-3 py-1 rounded-full">
            v3.0
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 py-6 space-y-8">

        {/* SECTION 1: Player Input */}
        <section className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
          <div className="flex items-center justify-between mb-6">
             <h2 className="text-xl font-bold text-slate-700 flex items-center gap-2">
                <Users className="text-emerald-500" />
                球員名單 
                <span className="text-sm font-normal text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">
                  {players.length} 人
                </span>
             </h2>
             <button 
                onClick={() => setPlayers([])} 
                className="text-xs text-slate-400 hover:text-red-400 flex items-center gap-1 transition-colors"
             >
                <Trash2 size={12} /> 清空名單
             </button>
          </div>

          {/* Add Player Form */}
          <form onSubmit={handleAddPlayer} className="flex flex-col sm:flex-row gap-3 mb-6 bg-slate-50 p-4 rounded-2xl border border-slate-100">
            <div className="flex-1">
              <input
                type="text"
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                placeholder="輸入新名字..."
                className="w-full px-4 py-3 rounded-xl border-2 border-transparent focus:border-emerald-300 focus:ring-0 focus:outline-none bg-white font-bold text-slate-700 placeholder:font-normal transition-all"
              />
            </div>

            <div className="flex bg-white rounded-xl p-1 shadow-sm w-full sm:w-auto">
              <button
                type="button"
                onClick={() => setNewGender(Gender.MALE)}
                className={`flex-1 sm:flex-none px-6 py-2 rounded-lg font-bold transition-all ${
                  newGender === Gender.MALE 
                    ? 'bg-blue-100 text-blue-600 shadow-sm' 
                    : 'text-slate-400 hover:text-slate-600'
                }`}
              >
                男生
              </button>
              <button
                type="button"
                onClick={() => setNewGender(Gender.FEMALE)}
                className={`flex-1 sm:flex-none px-6 py-2 rounded-lg font-bold transition-all ${
                  newGender === Gender.FEMALE 
                    ? 'bg-pink-100 text-pink-600 shadow-sm' 
                    : 'text-slate-400 hover:text-slate-600'
                }`}
              >
                女生
              </button>
            </div>

            <button
              type="submit"
              disabled={!newName.trim()}
              className="bg-emerald-500 hover:bg-emerald-600 disabled:opacity-50 disabled:cursor-not-allowed text-white px-6 py-3 rounded-xl font-bold shadow-lg shadow-emerald-200 transition-all flex items-center justify-center gap-2 active:scale-95"
            >
              <UserPlus size={18} />
              加入
            </button>
          </form>

          {/* History Quick Add */}
          {playerHistory.length > 0 && (
            <div className="mb-6">
              <div className="flex items-center justify-between mb-3">
                <div className="flex items-center gap-2 text-xs font-bold text-slate-400 uppercase tracking-wider">
                  <History size={12} /> 快速加入曾輸入的球員
                </div>
                <button 
                  onClick={handleAddAllHistory}
                  className="flex items-center gap-1.5 px-3 py-1.5 bg-emerald-50 hover:bg-emerald-100 text-emerald-600 rounded-lg text-xs font-bold transition-all border border-emerald-100 shadow-sm active:scale-95"
                  title="將歷史紀錄中尚未加入的球員全部加入"
                >
                  <Users size={14} /> 
                  全部加入
                </button>
              </div>

              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-2">
                {playerHistory.map((h) => {
                  const isActive = players.some(p => p.name === h.name);
                  return (
                    <div 
                      key={h.name} 
                      className={`
                        flex items-center border-2 rounded-xl transition-all duration-200 overflow-hidden
                        ${isActive 
                          ? 'bg-slate-50 border-slate-200 opacity-60' 
                          : h.gender === Gender.MALE 
                            ? 'bg-white border-blue-100 hover:border-blue-300 hover:shadow-md' 
                            : 'bg-white border-pink-100 hover:border-pink-300 hover:shadow-md'
                        }
                      `}
                    >
                      <button
                        onClick={() => !isActive && addPlayerLogic(h.name, h.gender)}
                        disabled={isActive}
                        className={`
                          flex-1 px-3 py-2 text-sm font-bold text-left truncate outline-none
                          ${isActive 
                            ? 'text-slate-400 cursor-default' 
                            : h.gender === Gender.MALE ? 'text-blue-600' : 'text-pink-600'
                          }
                        `}
                      >
                        {h.name}
                      </button>
                      <div className={`w-[2px] h-4 ${isActive ? 'bg-slate-200' : h.gender === Gender.MALE ? 'bg-blue-100' : 'bg-pink-100'}`}></div>
                      <button
                        onClick={(e) => removeFromHistory(e, h.name)}
                        className="px-2.5 py-2.5 text-slate-300 hover:text-red-500 hover:bg-red-50 transition-colors outline-none flex items-center justify-center"
                      >
                        <Trash2 size={14} />
                      </button>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Active Player Grid */}
          <div className="min-h-[100px]">
            {players.length === 0 ? (
              <div className="text-center py-8 text-slate-300 rounded-2xl border-2 border-dashed border-slate-100 bg-slate-50/50">
                <p>名單是空的，快從上面加入或選擇歷史紀錄！</p>
              </div>
            ) : (
              <div className="flex flex-wrap gap-3">
                {players.map(player => (
                  <PlayerCard 
                    key={player.id} 
                    player={player} 
                    onDelete={handleDeletePlayer} 
                  />
                ))}
              </div>
            )}
          </div>
        </section>

        {errorMsg && (
          <div className="bg-red-100 border-2 border-red-200 text-red-600 px-4 py-3 rounded-2xl text-center font-bold animate-pulse shadow-sm">
            🚨 {errorMsg}
          </div>
        )}

        {/* SECTION 2: Modes Tab */}
        <section className="grid grid-cols-1 lg:grid-cols-2 gap-6">

          {/* Quick Match Mode */}
          <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex flex-col h-full">
            <div className="flex items-center gap-2 mb-4">
               <div className="p-2 bg-blue-100 rounded-lg text-blue-600"><Shuffle size={20} /></div>
               <h3 className="text-lg font-bold text-slate-700">快速隨機分隊</h3>
            </div>
            <p className="text-sm text-slate-400 mb-6 flex-1">
              根據目前球員名單，隨機產生一場或多場比賽。適合即時上場使用。
