                   className="flex-1 px-4 py-3 rounded-xl border-none font-bold text-emerald-800 bg-white/80 focus:ring-2 focus:ring-emerald-400 outline-none cursor-pointer"
                 >
                   <option value={MatchType.RANDOM}>一般隨機</option>
                   <option value={MatchType.MIXED_DOUBLES}>男女混雙</option>
                   <option value={MatchType.MENS_DOUBLES}>男雙</option>
                   <option value={MatchType.WOMENS_DOUBLES}>女雙</option>
                 </select>
                 <button 
