                    <h3>本輪休息 ({waitingPlayers.length} 人)</h3>
                  </div>
                  <div className="flex flex-wrap gap-3">
                    {waitingPlayers.map(p => (
                      <PlayerCard key={p.id} player={p} />
                    ))}
                  </div>
                </section>
              )}
            </section>
          )}

          {/* Schedule Results */}
          {isScheduleMode && schedule.length > 0 && (
            <section className="space-y-6 animate-in slide-in-from-bottom-10 fade-in duration-500">
               <div className="flex items-center justify-between gap-4 mb-6">
                   <div className="flex items-center gap-3">
                       <div className="h-1 w-8 bg-slate-200 rounded-full"></div>
                       <h3 className="text-xl font-bold text-emerald-700 whitespace-nowrap flex items-center gap-2">
                          <Calendar className="inline" /> 賽程表 ({schedule.length} 場)
                       </h3>
                       <div className="h-1 w-8 bg-slate-200 rounded-full"></div>
                   </div>

                   <button 
                     onClick={handleExport}
                     className="bg-emerald-100 hover:bg-emerald-200 text-emerald-700 px-4 py-2 rounded-xl font-bold shadow-sm transition-all flex items-center gap-2 active:scale-95 text-sm whitespace-nowrap"
                   >
                     <Download size={16} />
                     匯出圖片
                   </button>
               </div>

               <div className="overflow-hidden rounded-xl border border-emerald-100">
                   {/* Capture Area */}
                   <div ref={scheduleRef} className="bg-emerald-50/50 p-6 md:p-8">
                      {/* Export Header */}
                      <div className="flex flex-col items-center justify-center mb-8 text-center">
                          <div className="bg-emerald-500 text-white p-3 rounded-2xl shadow-lg mb-3">
                              <Shuffle size={32} />
                          </div>
                          <h2 className="text-3xl font-black text-emerald-800 tracking-tight mb-1">菜雞互啄分隊趣</h2>
                          <div className="text-emerald-600 font-bold bg-emerald-100/50 px-4 py-1 rounded-full text-sm">
                              {new Date().toLocaleDateString('zh-TW', { year: 'numeric', month: 'long', day: 'numeric' })} • 賽程表
                          </div>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {schedule.map((match, idx) => (
                          <div key={match.id} className="bg-white rounded-xl p-3 shadow-sm border border-emerald-100 flex items-center gap-3 relative overflow-hidden group">
                             {/* Sequence Number */}
                             <div className="bg-slate-100 text-slate-500 w-8 h-8 rounded-full flex items-center justify-center font-black text-sm shrink-0 shadow-inner">
                               {match.sequence}
                             </div>

                             {/* Teams Container */}
                             <div className="flex-1 grid grid-cols-[1fr_auto_1fr] items-center gap-2">
                                {/* Team A */}
                                <div className="flex flex-col gap-1 items-end min-w-0">
                                   <PlayerCard player={match.teamA.player1} size="sm" autoWidth className="justify-end w-full" />
                                   <PlayerCard player={match.teamA.player2} size="sm" autoWidth className="justify-end w-full" />
                                </div>

                                {/* VS */}
                                <div className="text-slate-300 font-black italic text-xs px-1">VS</div>

                                {/* Team B */}
                                <div className="flex flex-col gap-1 items-start min-w-0">
                                   <PlayerCard player={match.teamB.player1} size="sm" autoWidth className="w-full" />
                                   <PlayerCard player={match.teamB.player2} size="sm" autoWidth className="w-full" />
                                </div>
                             </div>

                             {match.message && (
                               <div className="absolute top-0 right-0 text-[10px] bg-yellow-100 text-yellow-800 px-1.5 py-0.5 rounded-bl-lg font-bold">
                                 {match.message}
                               </div>
                             )}
                          </div>
                        ))}
                      </div>

                      {/* Export Footer */}
                      <div className="mt-8 flex items-center justify-between text-emerald-800/40 border-t border-emerald-800/10 pt-4">
                        <span className="text-xs font-bold">Generated by 菜雞互啄分隊趣</span>
                        <span className="text-xs font-bold">智慧輪替 • 自動排程</span>
                      </div>
                  </div>
               </div>
            </section>
          )}

          {/* Empty State */}
          {matches.length === 0 && schedule.length === 0 && !errorMsg && (
             <div className="text-center py-12 opacity-50">
               <div className="inline-block p-6 rounded-full bg-slate-100 mb-4">
                  <ArrowRight size={48} className="text-slate-300 rotate-90 md:rotate-0" />
               </div>
               <p className="text-slate-400 font-medium">選擇上方功能開始分隊或排程</p>
             </div>
          )}
        </div>

      </main>

      {/* Decoration */}
      <div className="fixed -bottom-10 -left-10 text-emerald-100 opacity-50 pointer-events-none rotate-12">
        <svg width="200" height="200" viewBox="0 0 24 24" fill="currentColor"><path d="M12.5 2C12.5 2 12.5 5 15 7.5C17.5 10 20.5 10 20.5 10L22 13L18.5 14L15.5 21L12.5 18L9.5 21L6.5 14L3 13L4.5 10C4.5 10 7.5 10 10 7.5C12.5 5 12.5 2 12.5 2Z" /></svg>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Player, Gender, Match, MatchType, ScheduleItem } from './types';
import { generateMatches, generateSchedule } from './services/matchService';
import Court from './components/Court';
import PlayerCard from './components/PlayerCard';
import { Trash2, Shuffle, UserPlus, Users, History, Coffee, XCircle, RefreshCw, X, Calendar, Settings, ArrowRight, CheckCircle2, Circle, Download, Shield, Volume2 } from 'lucide-react';
import html2canvas from 'html2canvas';

interface HistoryPlayer {
  name: string;
  gender: Gender;
}

const App: React.FC = () => {
  const [players, setPlayers] = useState<Player[]>([]);
  const [newName, setNewName] = useState('');
  const [newGender, setNewGender] = useState<Gender>(Gender.MALE);

  // Single Match Mode State
  const [matches, setMatches] = useState<Match[]>([]);
  const [waitingPlayers, setWaitingPlayers] = useState<Player[]>([]);

  // Schedule Mode State
  const [schedule, setSchedule] = useState<ScheduleItem[]>([]);
  const [rounds, setRounds] = useState<number>(2);
  const [scheduleType, setScheduleType] = useState<MatchType>(MatchType.RANDOM);
  const [isScheduleMode, setIsScheduleMode] = useState<boolean>(false);
  const [mixPartners, setMixPartners] = useState<boolean>(true); // New state for mixing partners
  const [avoidGenderSkew, setAvoidGenderSkew] = useState<boolean>(false); // State for avoiding MM vs FF

  const [lastMatchType, setLastMatchType] = useState<MatchType | null>(null);

  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [playerHistory, setPlayerHistory] = useState<HistoryPlayer[]>([]);

  const scheduleRef = useRef<HTMLDivElement>(null);

  // Load history on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('badminton_player_history');
    if (savedHistory) {
      try {
        setPlayerHistory(JSON.parse(savedHistory));
      } catch (e) {
        console.error("Failed to parse history", e);
      }
    }
  }, []);

  // Save history helper
  const addToHistory = (name: string, gender: Gender) => {
    setPlayerHistory(prev => {
      const exists = prev.some(p => p.name === name);
      if (exists) return prev;
      const newHistory = [...prev, { name, gender }];
      localStorage.setItem('badminton_player_history', JSON.stringify(newHistory));
      return newHistory;
    });
  };

  const removeFromHistory = (e: React.MouseEvent, nameToDelete: string) => {
    e.stopPropagation();
    const newHistory = playerHistory.filter(p => p.name !== nameToDelete);
    setPlayerHistory(newHistory);
    localStorage.setItem('badminton_player_history', JSON.stringify(newHistory));
  };

  const handleAddPlayer = (e: React.FormEvent) => {
    e.preventDefault();
    addPlayerLogic(newName, newGender);
    setNewName('');
  };

  const addPlayerLogic = (name: string, gender: Gender) => {
    if (!name.trim()) return;

    // Prevent duplicates in current list
    if (players.some(p => p.name === name)) {
      setErrorMsg(`${name} 已經在名單中囉！`);
      setTimeout(() => setErrorMsg(null), 2000);
      return;
    }

    const newPlayer: Player = {
      id: Date.now().toString() + Math.random().toString(),
      name: name.trim(),
      gender: gender,
    };

    setPlayers([...players, newPlayer]);
    addToHistory(name.trim(), gender);
  };

  const handleAddAllHistory = () => {
    const currentNames = new Set(players.map(p => p.name));
    const playersToAdd: Player[] = [];

    playerHistory.forEach((h, index) => {
      if (!currentNames.has(h.name)) {
        playersToAdd.push({
          id: Date.now().toString() + '-' + index + '-' + Math.random().toString().substr(2, 5),
          name: h.name,
          gender: h.gender,
        });
      }
    });

    if (playersToAdd.length > 0) {
      setPlayers(prev => [...prev, ...playersToAdd]);
    } else {
       setErrorMsg('所有歷史球員都在名單內囉！');
       setTimeout(() => setErrorMsg(null), 2000);
    }
  };

  const handleDeletePlayer = (id: string) => {
    setPlayers(players.filter(p => p.id !== id));
  };

  // --- SINGLE MATCH GENERATION ---
  const handleGenerate = (type: MatchType) => {
    setErrorMsg(null);
    setIsScheduleMode(false);
    setLastMatchType(type);
    setMatches([]);
    setWaitingPlayers([]);

    const result = generateMatches(players, type);

    if (result.error) {
      setErrorMsg(result.error);
      setTimeout(() => setErrorMsg(null), 3000);
    } else {
      setMatches(result.matches);
      setWaitingPlayers(result.waiting);
      scrollToResults();
    }
  };

  const handleReshuffle = () => {
    if (!lastMatchType) return;
    setErrorMsg(null);

    const result = generateMatches(players, lastMatchType, matches);

    if (result.error) {
        setErrorMsg(result.error);
        setTimeout(() => setErrorMsg(null), 3000);
    } else {
        setMatches(result.matches);
        setWaitingPlayers(result.waiting);
    }
  };

  // --- SCHEDULE GENERATION ---
  const handleGenerateSchedule = () => {
    setErrorMsg(null);
    setIsScheduleMode(true);
    setSchedule([]);

    const result = generateSchedule(players, rounds, mixPartners, avoidGenderSkew, scheduleType);

    if (result.error) {
        setErrorMsg(result.error);
        setTimeout(() => setErrorMsg(null), 3000);
    } else {
        setSchedule(result.schedule);
        scrollToResults();
    }
  };

  const scrollToResults = () => {
    setTimeout(() => {
        document.getElementById('results-section')?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const handleExport = async () => {
    if (!scheduleRef.current) return;

    try {
        const canvas = await html2canvas(scheduleRef.current, {
            scale: 2, // High resolution
            backgroundColor: '#f0fdf4', // Match body bg (emerald-50)
            useCORS: true,
            logging: false,
            windowWidth: 1024, // Force desktop width to ensure 2-column layout even on mobile
        });

        const link = document.createElement('a');
        link.download = `badminton-schedule-${new Date().toISOString().slice(0,10)}.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();
    } catch (error) {
        console.error('Export failed:', error);
        alert('圖片匯出失敗，請稍後再試');
    }
  };

  const handleSpeak = (match: ScheduleItem) => {
    window.speechSynthesis.cancel();
    const text = `第${match.sequence}場，${match.teamA.player1.name} 與 ${match.teamA.player2.name}，對戰，${match.teamB.player1.name} 與 ${match.teamB.player2.name}`;
    const u = new SpeechSynthesisUtterance(text);
    u.lang = 'zh-TW';
    u.rate = 0.9;
    window.speechSynthesis.speak(u);
  };

  return (
    <div className="min-h-screen bg-slate-50 font-q pb-20">
      {/* Header */}
      <header className="bg-white shadow-sm border-b border-slate-200 sticky top-0 z-30">
        <div className="max-w-4xl mx-auto px-4 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-500 p-2 rounded-xl text-white shadow-emerald-200 shadow-lg">
               <Shuffle size={24} />
            </div>
            <h1 className="text-2xl font-bold text-slate-700 tracking-tight">
              菜雞互啄 <span className="text-emerald-500">分隊趣</span>
            </h1>
          </div>
          <div className="text-xs text-slate-400 font-medium bg-slate-100 px-3 py-1 rounded-full">
            v3.3
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 py-6 space-y-8">

        {/* SECTION 1: Player Input */}
        <section className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
          <div className="flex items-center justify-between mb-6">
             <h2 className="text-xl font-bold text-slate-700 flex items-center gap-2">
                <Users className="text-emerald-500" />
                球員名單 
                <span className="text-sm font-normal text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">
                  {players.length} 人
                </span>
             </h2>
             <button 
                onClick={() => setPlayers([])} 
                className="text-xs text-slate-400 hover:text-red-400 flex items-center gap-1 transition-colors"
             >
                <Trash2 size={12} /> 清空名單
             </button>
          </div>

          {/* Add Player Form */}
          <form onSubmit={handleAddPlayer} className="flex flex-col sm:flex-row gap-3 mb-6 bg-slate-50 p-4 rounded-2xl border border-slate-100">
            <div className="flex-1">
              <input
                type="text"
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                placeholder="輸入新名字..."
                className="w-full px-4 py-3 rounded-xl border-2 border-transparent focus:border-emerald-300 focus:ring-0 focus:outline-none bg-white font-bold text-slate-700 placeholder:font-normal transition-all"
              />
            </div>

            <div className="flex bg-white rounded-xl p-1 shadow-sm w-full sm:w-auto">
              <button
                type="button"
                onClick={() => setNewGender(Gender.MALE)}
                className={`flex-1 sm:flex-none px-6 py-2 rounded-lg font-bold transition-all ${
                  newGender === Gender.MALE 
                    ? 'bg-blue-100 text-blue-600 shadow-sm' 
                    : 'text-slate-400 hover:text-slate-600'
                }`}
              >
                男生
              </button>
              <button
                type="button"
                onClick={() => setNewGender(Gender.FEMALE)}
                className={`flex-1 sm:flex-none px-6 py-2 rounded-lg font-bold transition-all ${
                  newGender === Gender.FEMALE 
                    ? 'bg-pink-100 text-pink-600 shadow-sm' 
                    : 'text-slate-400 hover:text-slate-600'
                }`}
              >
                女生
              </button>
            </div>

            <button
              type="submit"
              disabled={!newName.trim()}
              className="bg-emerald-500 hover:bg-emerald-600 disabled:opacity-50 disabled:cursor-not-allowed text-white px-6 py-3 rounded-xl font-bold shadow-lg shadow-emerald-200 transition-all flex items-center justify-center gap-2 active:scale-95"
            >
              <UserPlus size={18} />
              加入
            </button>
          </form>

          {/* History Quick Add */}
          {playerHistory.length > 0 && (
            <div className="mb-6">
              <div className="flex items-center justify-between mb-3">
                <div className="flex items-center gap-2 text-xs font-bold text-slate-400 uppercase tracking-wider">
                  <History size={12} /> 快速加入曾輸入的球員
                </div>
                <button 
                  onClick={handleAddAllHistory}
                  className="flex items-center gap-1.5 px-3 py-1.5 bg-emerald-50 hover:bg-emerald-100 text-emerald-600 rounded-lg text-xs font-bold transition-all border border-emerald-100 shadow-sm active:scale-95"
                  title="將歷史紀錄中尚未加入的球員全部加入"
                >
                  <Users size={14} /> 
                  全部加入
                </button>
              </div>

              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-2">
                {playerHistory.map((h) => {
                  const isActive = players.some(p => p.name === h.name);
                  return (
                    <div 
                      key={h.name} 
                      className={`
                        flex items-center border-2 rounded-xl transition-all duration-200 overflow-hidden
                        ${isActive 
                          ? 'bg-slate-50 border-slate-200 opacity-60' 
                          : h.gender === Gender.MALE 
                            ? 'bg-white border-blue-100 hover:border-blue-300 hover:shadow-md' 
                            : 'bg-white border-pink-100 hover:border-pink-300 hover:shadow-md'
                        }
                      `}
                    >
                      <button
                        onClick={() => !isActive && addPlayerLogic(h.name, h.gender)}
                        disabled={isActive}
                        className={`
                          flex-1 px-3 py-2 text-sm font-bold text-left truncate outline-none
                          ${isActive 
                            ? 'text-slate-400 cursor-default' 
                            : h.gender === Gender.MALE ? 'text-blue-600' : 'text-pink-600'
                          }
                        `}
                      >
                        {h.name}
                      </button>
                      <div className={`w-[2px] h-4 ${isActive ? 'bg-slate-200' : h.gender === Gender.MALE ? 'bg-blue-100' : 'bg-pink-100'}`}></div>
                      <button
                        onClick={(e) => removeFromHistory(e, h.name)}
                        className="px-2.5 py-2.5 text-slate-300 hover:text-red-500 hover:bg-red-50 transition-colors outline-none flex items-center justify-center"
                      >
                        <Trash2 size={14} />
                      </button>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Active Player Grid */}
          <div className="min-h-[100px]">
            {players.length === 0 ? (
              <div className="text-center py-8 text-slate-300 rounded-2xl border-2 border-dashed border-slate-100 bg-slate-50/50">
                <p>名單是空的，快從上面加入或選擇歷史紀錄！</p>
              </div>
            ) : (
              <div className="flex flex-wrap gap-3">
                {players.map(player => (
                  <PlayerCard 
                    key={player.id} 
                    player={player} 
                    onDelete={handleDeletePlayer} 
                  />
                ))}
              </div>
            )}
          </div>
        </section>

        {errorMsg && (
          <div className="bg-red-100 border-2 border-red-200 text-red-600 px-4 py-3 rounded-2xl text-center font-bold animate-pulse shadow-sm">
            🚨 {errorMsg}
          </div>
        )}

        {/* SECTION 2: Modes Tab */}
        <section className="grid grid-cols-1 lg:grid-cols-2 gap-6">

          {/* Quick Match Mode */}
          <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex flex-col h-full">
            <div className="flex items-center gap-2 mb-4">
               <div className="p-2 bg-blue-100 rounded-lg text-blue-600"><Shuffle size={20} /></div>
               <h3 className="text-lg font-bold text-slate-700">快速隨機分隊</h3>
            </div>
            <p className="text-sm text-slate-400 mb-6 flex-1">
              根據目前球員名單，隨機產生一場或多場比賽。適合即時上場使用。
            </p>
            <div className="grid grid-cols-2 gap-3">
               <button onClick={() => handleGenerate(MatchType.RANDOM)} className="py-3 bg-slate-100 hover:bg-emerald-100 hover:text-emerald-700 text-slate-600 rounded-xl font-bold transition-colors">隨機亂鬥</button>
               <button onClick={() => handleGenerate(MatchType.MIXED_DOUBLES)} className="py-3 bg-slate-100 hover:bg-purple-100 hover:text-purple-700 text-slate-600 rounded-xl font-bold transition-colors">混雙</button>
               <button onClick={() => handleGenerate(MatchType.MENS_DOUBLES)} className="py-3 bg-slate-100 hover:bg-blue-100 hover:text-blue-700 text-slate-600 rounded-xl font-bold transition-colors">男雙</button>
               <button onClick={() => handleGenerate(MatchType.WOMENS_DOUBLES)} className="py-3 bg-slate-100 hover:bg-pink-100 hover:text-pink-700 text-slate-600 rounded-xl font-bold transition-colors">女雙</button>
            </div>
          </div>

          {/* Schedule Generator Mode */}
          <div className="bg-emerald-50 p-6 rounded-3xl border border-emerald-100 shadow-sm flex flex-col h-full">
            <div className="flex items-center gap-2 mb-4">
               <div className="p-2 bg-emerald-200 rounded-lg text-emerald-800"><Calendar size={20} /></div>
               <h3 className="text-lg font-bold text-emerald-900">智慧賽程安排</h3>
            </div>
            <p className="text-sm text-emerald-700/70 mb-4 flex-1">
               自動排定多場次，並套用「連打二場必休二場、連休二場必打二場」的智慧輪替規則。
            </p>

            <div className="space-y-4">
              {/* Controls Grid */}
              <div className="grid grid-cols-2 gap-3">
                 <div className="flex items-center gap-2 bg-white/60 p-2 rounded-xl">
                   <span className="text-xs font-bold text-emerald-800 px-1">輪數:</span>
                   <button onClick={() => setRounds(Math.max(1, rounds-1))} className="w-6 h-6 rounded-md bg-white shadow-sm font-bold text-emerald-600 flex items-center justify-center hover:bg-emerald-100">-</button>
                   <span className="flex-1 text-center font-bold text-emerald-800">{rounds}</span>
                   <button onClick={() => setRounds(rounds+1)} className="w-6 h-6 rounded-md bg-white shadow-sm font-bold text-emerald-600 flex items-center justify-center hover:bg-emerald-100">+</button>
                 </div>

                 {/* Toggles */}
                 <div className="grid grid-cols-2 gap-2 col-span-2 md:col-span-1 md:grid-cols-1">
                    <button 
                    onClick={() => setMixPartners(!mixPartners)}
                    className={`flex items-center justify-center gap-2 p-2 rounded-xl border-2 transition-all ${
                        mixPartners 
                        ? 'bg-emerald-100 border-emerald-200 text-emerald-700' 
                        : 'bg-white/60 border-transparent text-slate-400'
                    }`}
                    >
                    {mixPartners ? <CheckCircle2 size={16} /> : <Circle size={16} />}
                    <span className="text-xs font-bold">盡量交換隊友</span>
                    </button>

                    <button 
                    onClick={() => setAvoidGenderSkew(!avoidGenderSkew)}
                    className={`flex items-center justify-center gap-2 p-2 rounded-xl border-2 transition-all ${
                        avoidGenderSkew 
                        ? 'bg-blue-100 border-blue-200 text-blue-700' 
                        : 'bg-white/60 border-transparent text-slate-400'
                    }`}
                    title="盡量避免兩位男生對戰兩位女生的組合"
                    >
                    {avoidGenderSkew ? <Shield size={16} /> : <Circle size={16} />}
                    <span className="text-xs font-bold">避免男男vs女女</span>
                    </button>
                 </div>
              </div>

              <div className="flex gap-2">
                 <select 
                   value={scheduleType} 
                   onChange={(e) => setScheduleType(e.target.value as MatchType)}
                   className="flex-1 px-4 py-3 rounded-xl border-none font-bold text-emerald-800 bg-white/80 focus:ring-2 focus:ring-emerald-400 outline-none cursor-pointer"
                 >
                   <option value={MatchType.RANDOM}>一般隨機</option>
                   <option value={MatchType.MIXED_DOUBLES}>男女混雙</option>
                   <option value={MatchType.MENS_DOUBLES}>男雙</option>
                   <option value={MatchType.WOMENS_DOUBLES}>女雙</option>
                 </select>
                 <button 
                   onClick={handleGenerateSchedule}
                   className="flex-1 bg-emerald-500 hover:bg-emerald-600 text-white font-bold rounded-xl shadow-lg shadow-emerald-200 transition-all active:scale-95 whitespace-nowrap"
                 >
                   產生賽程
                 </button>
              </div>
            </div>
